command.text:
        /* <flatten type="Javascript"> */
var f = this, id = f.get_id(), v = f._language == 'v', g = f.getItem('d91')._controlBehavior;
var l1 = g._getColumnOrder('tag1'), l2 = g._getColumnOrder('tag2');
var e1 = (v ? 'Dữ liệu không hợp lệ, các dòng trong chi tiết phải được chọn duyệt hoặc hủy.' : 'Invalid data, purchase requisition line has not been approved or cancelled.');
for (var i = 1; i <= g._rowCount; i++) {
  var v1 = g._getItemValue(i, l1), v2 = g._getItemValue(i, l2);
    if (!v1 && !v2) {
      $func.hideWait(id);
      f._errorWarningObject = g._getItem(i, l1);
      $message.show(e1, String.format('var f = $find(\'{0}\');f.focus(\'d91\');f._errorWarningObject.focus()', id));
      f._checked = false;
      break;
    }
  }
}/* </flatten> */

script.text:
      /* <flatten type="Javascript"> */
function load$Form(f) {setItemDisable(f, 'dept_id, ma_nk, so_ct, ong_ba, ngay_lct, ma_gd, status, ty_gia, ma_nt, dien_giai', true);}
function setItemDisable(f, c, v) {
  var a = c.split(',');
  for (var i = 0; i < a.length; i++) {
    var o = f.getItem($func.trim(a[i]));
    f._setReadOnly(o, v);
    o.disabled = v;
  }
}
function updateBrowse(f, d, h, t) {
  var g = f.grid;
  g.goToPage(-1);
}/* </flatten> */
